import { coachingPreferencesService, DEFAULT_WORKOUT_WINDOW } from '../../../services/coaching-preferences.service.js';
import { appTodayString, appTodayPlainDate } from '../../../services/app-timezone.service.js';
import { navigate } from '../../../router.js';
import { buildSectionPage } from '../../../utils/section-page.utils.js';
import { formatRelativeStamp } from '../../../utils/coaching-format.js';
import {
    createScreenStatusNodes,
    createScreenStatusMixin,
} from '../../_shared/screen-status.js';
import type { ScreenComponent } from '../../../types/screen-component.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { renderMarkdown } from '../../../utils/markdown.js';
import { documentStyleSheet } from '../../../utils/css.js';
import coachingStyles from './health-coaching-screen.css?inline';

documentStyleSheet(coachingStyles);

const template = document.createElement('template');
template.innerHTML = `
    <section class="coaching" data-testid="coaching-section">
        <header class="coaching__nav">
            <button type="button" class="coaching__step" data-testid="coaching-prev" aria-label="Previous day">‹</button>
            <h3 class="coaching__date" data-testid="coaching-date"></h3>
            <button type="button" class="coaching__step" data-testid="coaching-next" aria-label="Next day">›</button>
        </header>

        <button type="button" class="coaching__generate" data-testid="coaching-generate"></button>

        <div class="coaching__latest" data-testid="coaching-latest"></div>

        <p class="coaching__empty" data-testid="coaching-empty" hidden></p>

        <details class="coaching__history" data-testid="coaching-history" hidden>
            <summary data-testid="coaching-history-summary"></summary>
            <div class="coaching__history-list" data-testid="coaching-history-list"></div>
        </details>

        <details class="coaching__settings" data-testid="coaching-settings">
            <summary>Tune your coach</summary>
            <form class="coaching__settings-form" data-testid="coaching-settings-form">
                <label class="coaching__field">
                    <span>Goals</span>
                    <textarea name="goals" data-testid="coaching-goals-input" rows="3" placeholder="e.g. lose 5kg by August, sub-22 5k"></textarea>
                </label>
                <label class="coaching__field">
                    <span>Tone</span>
                    <textarea name="tone" data-testid="coaching-tone-input" rows="3" placeholder="e.g. blunt, no fluff"></textarea>
                </label>
                <fieldset class="coaching__field coaching__window">
                    <legend>Workout window</legend>
                    <label>From <input type="time" name="workout-start" data-testid="coaching-window-start"></label>
                    <label>to <input type="time" name="workout-end" data-testid="coaching-window-end"></label>
                </fieldset>
                <div class="coaching__settings-actions">
                    <button type="submit" data-testid="coaching-settings-save">Save</button>
                    <span class="coaching__settings-status" data-testid="coaching-settings-status" hidden>Saved</span>
                </div>
            </form>
        </details>

        <template class="coaching__entry-tpl">
            <article class="entry" data-testid="coaching-entry">
                <header class="entry__head">
                    <span class="entry__stamp" data-testid="entry-stamp"></span>
                    <button type="button" class="entry__edit" data-testid="entry-edit" hidden>Edit</button>
                </header>
                <div class="entry__body" data-testid="entry-body"></div>
                <form class="entry__edit-form" data-testid="entry-edit-form" hidden>
                    <textarea class="entry__edit-input" data-testid="entry-edit-input" rows="8"></textarea>
                    <div class="entry__edit-actions">
                        <button type="submit" data-testid="entry-save">Save</button>
                        <button type="button" class="entry__cancel" data-testid="entry-cancel">Cancel</button>
                        <span class="entry__edit-status" data-testid="entry-edit-status" hidden></span>
                    </div>
                </form>
            </article>
        </template>
    </section>
`;

function relativeDateLabel(date: string, today: Temporal.PlainDate): string {
    const d = Temporal.PlainDate.from(date);
    const diff = d.since(today).days;
    if (diff === 0) return 'Today';
    if (diff === 1) return 'Tomorrow';
    if (diff === -1) return 'Yesterday';
    return date;
}

export class HealthCoachingScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private status: ReturnType<typeof createScreenStatusMixin> | null = null;
    private statusNodes: ReturnType<typeof createScreenStatusNodes> | null = null;
    private dateEl: HTMLElement | null = null;
    private prevBtn: HTMLButtonElement | null = null;
    private nextBtn: HTMLButtonElement | null = null;
    private generateBtn: HTMLButtonElement | null = null;
    private latestEl: HTMLElement | null = null;
    private emptyEl: HTMLElement | null = null;
    private historyEl: HTMLDetailsElement | null = null;
    private historySummaryEl: HTMLElement | null = null;
    private historyListEl: HTMLElement | null = null;
    private settingsEl: HTMLElement | null = null;
    private entryTemplate: HTMLTemplateElement | null = null;
    private goalsInput: HTMLTextAreaElement | null = null;
    private toneInput: HTMLTextAreaElement | null = null;
    private windowStartInput: HTMLInputElement | null = null;
    private windowEndInput: HTMLInputElement | null = null;
    private settingsForm: HTMLFormElement | null = null;
    private settingsStatus: HTMLElement | null = null;
    private dateValue = '';
    private readonly log = createComponentLogger('health-coaching-screen');

    /**
     * The day whose briefings to show, set by `/health/coaching/:date`. Empty
     * means today. Every view is date-scoped (story 175) — the stepper moves
     * between days and generation targets the viewed day.
     */
    set date(value: string) {
        this.dateValue = value;
    }

    private get viewedDate(): string {
        return this.dateValue || appTodayString();
    }

    setLoading(): void {
        this.status?.setLoading();
    }
    setError(err: unknown): void {
        this.status?.setError(err);
    }
    clearStatus(): void {
        this.status?.clearStatus();
    }

    connectedCallback(): void {
        if (this.initialized) {
            void this.load();
            return;
        }
        this.initialized = true;

        const page = buildSectionPage(this, 'Coaching', 'health', '/health');
        page.content.appendChild(template.content.cloneNode(true));

        const q = <T extends HTMLElement>(sel: string) => page.content.querySelector<T>(sel);
        this.dateEl = q('[data-testid="coaching-date"]');
        this.prevBtn = q<HTMLButtonElement>('[data-testid="coaching-prev"]');
        this.nextBtn = q<HTMLButtonElement>('[data-testid="coaching-next"]');
        this.generateBtn = q<HTMLButtonElement>('[data-testid="coaching-generate"]');
        this.latestEl = q('[data-testid="coaching-latest"]');
        this.emptyEl = q('[data-testid="coaching-empty"]');
        this.historyEl = q<HTMLDetailsElement>('[data-testid="coaching-history"]');
        this.historySummaryEl = q('[data-testid="coaching-history-summary"]');
        this.historyListEl = q('[data-testid="coaching-history-list"]');
        this.settingsEl = q('[data-testid="coaching-settings"]');
        this.entryTemplate = q<HTMLTemplateElement>('.coaching__entry-tpl');
        this.goalsInput = q<HTMLTextAreaElement>('[data-testid="coaching-goals-input"]');
        this.toneInput = q<HTMLTextAreaElement>('[data-testid="coaching-tone-input"]');
        this.windowStartInput = q<HTMLInputElement>('[data-testid="coaching-window-start"]');
        this.windowEndInput = q<HTMLInputElement>('[data-testid="coaching-window-end"]');
        this.settingsForm = q<HTMLFormElement>('[data-testid="coaching-settings-form"]');
        this.settingsStatus = q('[data-testid="coaching-settings-status"]');

        this.statusNodes = createScreenStatusNodes();
        page.content.appendChild(this.statusNodes.loadingNode);
        page.content.appendChild(this.statusNodes.errorNode);
        page.content.appendChild(this.statusNodes.retryNode);
        this.status = createScreenStatusMixin(
            this.statusNodes.loadingNode,
            this.statusNodes.errorNode,
            this.statusNodes.retryNode,
        );

        this.statusNodes.retryNode.addEventListener('click', () => void this.load());
        this.prevBtn?.addEventListener('click', () => this.step(-1));
        this.nextBtn?.addEventListener('click', () => this.step(1));
        this.generateBtn?.addEventListener('click', () => void this.generate());
        this.settingsForm?.addEventListener('submit', (event) => {
            event.preventDefault();
            void this.savePreferences();
        });

        void this.loadPreferences();
        void this.load();
    }

    private step(deltaDays: number): void {
        const target = Temporal.PlainDate.from(this.viewedDate).add({ days: deltaDays }).toString();
        navigate(`/health/coaching/${target}`);
    }

    private async load(): Promise<void> {
        this.setLoading();
        try {
            const entries = await HealthService.fetchCoachingEntries(this.viewedDate);
            this.render(entries);
            this.clearStatus();
        } catch (err) {
            this.log.error('fetchCoachingEntries failed:', err);
            this.setError(err);
        }
    }

    private render(entries: CoachingAdvice[]): void {
        const today = appTodayPlainDate();
        const tomorrow = today.add({ days: 1 }).toString();
        const isToday = this.viewedDate === appTodayString();

        if (this.dateEl) this.dateEl.textContent = `Coaching — ${relativeDateLabel(this.viewedDate, today)}`;
        // Back is unbounded; forward is capped at tomorrow.
        if (this.nextBtn) this.nextBtn.disabled = this.viewedDate >= tomorrow;
        if (this.settingsEl) this.settingsEl.hidden = !isToday;

        const latest = entries[0] ?? null;
        this.renderGenerateButton(latest);

        // Latest entry (or empty state).
        if (this.latestEl) this.latestEl.replaceChildren();
        if (this.emptyEl) {
            if (latest) {
                this.emptyEl.hidden = true;
            } else {
                this.emptyEl.textContent = `No coaching for ${relativeDateLabel(this.viewedDate, today).toLowerCase()} yet — generate one.`;
                this.emptyEl.hidden = false;
            }
        }
        if (latest && this.latestEl) {
            this.latestEl.appendChild(this.buildEntry(latest));
        }

        // Older entries.
        const older = entries.slice(1);
        if (this.historyEl && this.historyListEl && this.historySummaryEl) {
            this.historyListEl.replaceChildren();
            if (older.length > 0) {
                this.historySummaryEl.textContent = `${older.length} earlier briefing${older.length === 1 ? '' : 's'}`;
                for (const entry of older) {
                    this.historyListEl.appendChild(this.buildEntry(entry));
                }
                this.historyEl.hidden = false;
            } else {
                this.historyEl.hidden = true;
            }
        }
    }

    private renderGenerateButton(latest: CoachingAdvice | null): void {
        if (!this.generateBtn) return;
        const status = latest?.status;
        if (status === 'pending') {
            this.generateBtn.textContent = 'Queued…';
            this.generateBtn.disabled = true;
        } else if (status === 'done') {
            this.generateBtn.textContent = 'Re-generate';
            this.generateBtn.disabled = false;
        } else if (status === 'failed') {
            this.generateBtn.textContent = 'Retry';
            this.generateBtn.disabled = false;
        } else {
            this.generateBtn.textContent = 'Generate coaching';
            this.generateBtn.disabled = false;
        }
    }

    private buildEntry(entry: CoachingAdvice): HTMLElement {
        const fragment = this.entryTemplate!.content.cloneNode(true) as DocumentFragment;
        const root = fragment.querySelector<HTMLElement>('[data-testid="coaching-entry"]')!;
        const stampEl = root.querySelector<HTMLElement>('[data-testid="entry-stamp"]')!;
        const bodyEl = root.querySelector<HTMLElement>('[data-testid="entry-body"]')!;
        const editBtn = root.querySelector<HTMLButtonElement>('[data-testid="entry-edit"]')!;
        const form = root.querySelector<HTMLFormElement>('[data-testid="entry-edit-form"]')!;
        const input = root.querySelector<HTMLTextAreaElement>('[data-testid="entry-edit-input"]')!;
        const cancelBtn = root.querySelector<HTMLButtonElement>('[data-testid="entry-cancel"]')!;
        const editStatus = root.querySelector<HTMLElement>('[data-testid="entry-edit-status"]')!;

        const today = appTodayString();
        if (entry.status === 'done') {
            const edited = entry.updated_at ? ' · edited' : '';
            stampEl.textContent = formatRelativeStamp(entry.generated_at, today) + edited;
            // Story 203: the model writes markdown; render it to DOM nodes (no
            // innerHTML) via the shared renderer. Heading base 4 keeps any `#`
            // below the screen's date heading (h3). The edit flow seeds its
            // textarea from `entry.advice` (the record), not this rendered DOM,
            // so rendering can't corrupt the editable source.
            bodyEl.replaceChildren(renderMarkdown(entry.advice ?? '', {
                baseHeadingLevel: 4,
                onUnknownToken: (token) => this.log.warn('unknown markdown token in advice', { type: token.type }),
            }));
            editBtn.hidden = false;
        } else if (entry.status === 'pending') {
            stampEl.textContent = 'Queued — generating on the next run';
            bodyEl.textContent = '';
        } else {
            // failed — surface the raw error inline (fail-loud).
            stampEl.textContent = 'Generation failed';
            bodyEl.classList.add('entry__body--error');
            bodyEl.textContent = entry.error ?? 'Coaching generation failed without an error message.';
        }

        editBtn.addEventListener('click', () => {
            input.value = entry.advice ?? '';
            editStatus.hidden = true;
            bodyEl.hidden = true;
            editBtn.hidden = true;
            form.hidden = false;
            input.focus();
        });
        const exitEdit = () => {
            form.hidden = true;
            bodyEl.hidden = false;
            editBtn.hidden = false;
        };
        cancelBtn.addEventListener('click', exitEdit);
        form.addEventListener('submit', (event) => {
            event.preventDefault();
            void this.saveEdit(entry.id, input.value, editStatus);
        });

        return root;
    }

    private async saveEdit(id: string, advice: string, statusEl: HTMLElement): Promise<void> {
        try {
            await HealthService.updateCoachingAdvice(id, advice);
            await this.load();
        } catch (err) {
            this.log.error('updateCoachingAdvice failed:', err);
            statusEl.hidden = false;
            statusEl.textContent = err instanceof Error ? `Save failed: ${err.message}` : 'Save failed';
        }
    }

    private async generate(): Promise<void> {
        if (this.generateBtn) this.generateBtn.disabled = true;
        try {
            await HealthService.requestCoachingGeneration(this.viewedDate);
            await this.load();
        } catch (err) {
            this.log.error('requestCoachingGeneration failed:', err);
            this.setError(err);
        }
    }

    private async loadPreferences(): Promise<void> {
        try {
            const prefs = await coachingPreferencesService.get();
            if (this.goalsInput) this.goalsInput.value = prefs.goals;
            if (this.toneInput) this.toneInput.value = prefs.tone;
            if (this.windowStartInput) this.windowStartInput.value = prefs.workoutWindow.start;
            if (this.windowEndInput) this.windowEndInput.value = prefs.workoutWindow.end;
        } catch (err) {
            this.log.error('coachingPreferencesService.get failed:', err);
        }
    }

    private async savePreferences(): Promise<void> {
        if (!this.goalsInput || !this.toneInput) return;
        try {
            await coachingPreferencesService.set({
                goals: this.goalsInput.value,
                tone: this.toneInput.value,
                // Empty time inputs fall back to the default window rather than
                // writing an invalid blank the server can't parse.
                workoutWindow: {
                    start: this.windowStartInput?.value || DEFAULT_WORKOUT_WINDOW.start,
                    end: this.windowEndInput?.value || DEFAULT_WORKOUT_WINDOW.end,
                },
            });
            if (this.settingsStatus) {
                this.settingsStatus.hidden = false;
                this.settingsStatus.textContent = 'Saved';
            }
        } catch (err) {
            this.log.error('coachingPreferencesService.set failed:', err);
            if (this.settingsStatus) {
                this.settingsStatus.hidden = false;
                this.settingsStatus.textContent = err instanceof Error ? `Save failed: ${err.message}` : 'Save failed';
            }
        }
    }
}

if (!customElements.get('health-coaching-screen')) {
    customElements.define('health-coaching-screen', HealthCoachingScreen);
}
